def _dynamo_db_attribute_to_nested(
    dynamo_db_attribute: DynamoDBAttribute,
) -> DynamoDBAttributeNested:
    """Convert flat DynamoDBAttribute to nested format."""
    attrs = DynamoDBAttributeAttributes()
    _populate_dynamo_db_attribute_attrs(attrs, dynamo_db_attribute)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dynamo_db_attribute,
        _DYNAMO_DB_ATTRIBUTE_REL_FIELDS,
        DynamoDBAttributeRelationshipAttributes,
    )
    return DynamoDBAttributeNested(
        guid=dynamo_db_attribute.guid,
        type_name=dynamo_db_attribute.type_name,
        status=dynamo_db_attribute.status,
        version=dynamo_db_attribute.version,
        create_time=dynamo_db_attribute.create_time,
        update_time=dynamo_db_attribute.update_time,
        created_by=dynamo_db_attribute.created_by,
        updated_by=dynamo_db_attribute.updated_by,
        classifications=dynamo_db_attribute.classifications,
        classification_names=dynamo_db_attribute.classification_names,
        meanings=dynamo_db_attribute.meanings,
        labels=dynamo_db_attribute.labels,
        business_attributes=dynamo_db_attribute.business_attributes,
        custom_attributes=dynamo_db_attribute.custom_attributes,
        pending_tasks=dynamo_db_attribute.pending_tasks,
        proxy=dynamo_db_attribute.proxy,
        is_incomplete=dynamo_db_attribute.is_incomplete,
        provenance_type=dynamo_db_attribute.provenance_type,
        home_id=dynamo_db_attribute.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dynamo_db_attribute_from_nested(
    nested: DynamoDBAttributeNested,
) -> DynamoDBAttribute:
    """Convert nested format to flat DynamoDBAttribute."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DynamoDBAttributeAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DYNAMO_DB_ATTRIBUTE_REL_FIELDS,
        DynamoDBAttributeRelationshipAttributes,
    )
    return DynamoDBAttribute(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_dynamo_db_attribute_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dynamo_db_attribute_to_nested_bytes(
    dynamo_db_attribute: DynamoDBAttribute, serde: Serde
) -> bytes:
    """Convert flat DynamoDBAttribute to nested JSON bytes."""
    return serde.encode(_dynamo_db_attribute_to_nested(dynamo_db_attribute))


def _dynamo_db_attribute_from_nested_bytes(
    data: bytes, serde: Serde
) -> DynamoDBAttribute:
    """Convert nested JSON bytes to flat DynamoDBAttribute."""
    nested = serde.decode(data, DynamoDBAttributeNested)
    return _dynamo_db_attribute_from_nested(nested)


